Certainly! Below is an optimized C++ code to calculate the derivative of a given mathematical function. This example uses a simple polynomial function for demonstration, but it can be extended to more complex functions.

```cpp
#include <iostream>
#include <vector>

class Polynomial {
public:
    std::vector<int> coefficients;

    Polynomial(const std::vector<int>& coeffs) : coefficients(coeffs) {}

    Polynomial& operator+=(const Polynomial& other) {
        size_t maxSize = std::max(coefficients.size(), other.coefficients.size());
        coefficients.resize(maxSize);
        for (size_t i = 0; i < other.coefficients.size(); ++i) {
            coefficients[i] += other.coefficients[i];
        }
        return *this;
    }

    Polynomial& operator-=(const Polynomial& other) {
        size_t maxSize = std::max(coefficients.size(), other.coefficients.size());
        coefficients.resize(maxSize);
        for (size_t i = 0; i < other.coefficients.size(); ++i) {
            coefficients[i] -= other.coefficients[i];
        }
        return *this;
    }

    Polynomial& operator*=(int scalar) {
        for (auto& coeff : coefficients) {
            coeff *= scalar;
        }
        return *this;
    }

    Polynomial derivative() const {
        Polynomial result;
        for (size_t i = 1; i < coefficients.size(); ++i) {
            result.coefficients.push_back(i * coefficients[i]);
        }
        return result;
    }
};

void printPolynomial(const Polynomial& poly) {
    for (size_t i = poly.coefficients.size() - 1; i > 0; --i) {
        std::cout << poly.coefficients[i] << "x^" << i << " + ";
    }
    if (!poly.coefficients.empty()) {
        std::cout << poly.coefficients.front();
    }
    std::cout << std::endl;
}

int main() {
    // Example: (3x^2 + 2x + 1)
    Polynomial p({3, 2, 1});
    std::cout << "Original Polynomial: ";
    printPolynomial(p);

    Polynomial deriv = p.derivative();
    std::cout << "Derivative: ";
    printPolynomial(deriv);

    return 0;
}
```

